const fs = require('fs');
const body = $input.first().json.body;
const alert = body?.alerts?.[0] || {};
const labels = alert.labels || {};
const annotations = alert.annotations || {};
const alertname = labels.alertname || 'Unknown';
const severity = labels.severity || 'warning';
const ns = labels.namespace || 'apps';
const deployment = labels.deployment || '';
const jobName = labels.job_name || '';
const summary = annotations.summary || '';
const description = annotations.description || '';
const status = body.status || '';

let token = '';
try {
  token = fs.readFileSync('/var/run/secrets/kubernetes.io/serviceaccount/token', 'utf8').trim();
} catch (e) {
  return [{ json: {
    alertname, severity, namespace: ns, deployment, job_name: jobName,
    summary, description, status, podName: '', logs: 'No K8s token: ' + e.message
  }}];
}

let podName = '';
let logs = '';

try {
  let labelSelector = '';
  if (alertname === 'MundadosPortalDown') {
    labelSelector = 'app=mundados-portal';
  } else if (jobName) {
    labelSelector = 'job-name=' + jobName;
  } else if (alertname === 'MundadosRecolhaMissed') {
    labelSelector = 'app=mundados-recolha';
  } else {
    labelSelector = 'app=mundados';
  }

  const podsResp = await fetch(
    'https://kubernetes.default.svc/api/v1/namespaces/' + ns + '/pods?labelSelector=' + labelSelector,
    { headers: { 'Authorization': 'Bearer ' + token } }
  );
  const podsData = await podsResp.json();
  const pods = podsData.items || [];
  podName = pods.length > 0 ? pods[0].metadata.name : '';

  if (podName) {
    const logResp = await fetch(
      'https://kubernetes.default.svc/api/v1/namespaces/' + ns + '/pods/' + podName + '/log?tailLines=50',
      { headers: { 'Authorization': 'Bearer ' + token } }
    );
    logs = await logResp.text();
  } else {
    logs = 'No pods found for selector: ' + labelSelector;
  }
} catch (e) {
  logs = 'Failed to fetch logs: ' + e.message;
}

return [{ json: {
  alertname, severity, namespace: ns, deployment, job_name: jobName,
  summary, description, status, podName, logs
}}];

